import sys
from math import gcd

input = sys.stdin.readline

def solve():
    n = int(input())
    a = list(map(int, input().split()))
    if n == 1:
        print(1)
        return

    d = [abs(a[i+1] - a[i]) for i in range(n-1)]

    best = 1
    # current: list of (gcd_value, start_index_in_d) with distinct gcd values
    current = []

    for i, x in enumerate(d):
        new_current = []
        for g, start in current:
            ng = gcd(g, x)
            if new_current and new_current[-1][0] == ng:
                # keep the earlier start (larger subarray)
                pass  # new_current[-1] already has earlier start
            else:
                new_current.append((ng, start))
        # Add subarray starting at i (just x itself)
        if new_current and new_current[-1][0] == x:
            pass  # already covered
        else:
            new_current.append((x, i))
        current = new_current

        for g, start in current:
            if g >= 2:
                length_in_d = i - start + 1
                best = max(best, length_in_d + 1)

    print(best)

t = int(input())
for _ in range(t):
    solve()

